import React, { useState, useRef } from 'react';
import { User, View, UserRole } from '../types';
import { Camera, Upload, MapPin, Loader2, X } from 'lucide-react';

interface AuthProps {
  onLogin: (user: User) => void;
  setCurrentView: (view: View) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin, setCurrentView }) => {
  const [loading, setLoading] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);
  const [isProcessingImage, setIsProcessingImage] = useState(false);
  const [formData, setFormData] = useState({
    email: '',
    username: '',
    password: '',
    location: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        alert("حجم الصورة كبير جداً. يرجى اختيار صورة أقل من 5 ميجابايت.");
        if (fileInputRef.current) fileInputRef.current.value = '';
        return;
      }

      setIsProcessingImage(true);
      const reader = new FileReader();

      reader.onload = () => {
        if (typeof reader.result === 'string') {
          setAvatarPreview(reader.result);
        }
        setIsProcessingImage(false);
      };

      reader.onerror = () => {
        alert("حدث خطأ أثناء معالجة الصورة. يرجى المحاولة مرة أخرى.");
        setIsProcessingImage(false);
      };

      reader.readAsDataURL(file);
    }
    // Reset so same file can be re-selected if cleared
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  const clearImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setAvatarPreview(null);
  };

  const handleGetLocation = () => {
    setLocationLoading(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const { latitude, longitude } = position.coords;
          setFormData(prev => ({ ...prev, location: `${latitude.toFixed(4)}, ${longitude.toFixed(4)}` }));
          setLocationLoading(false);
        },
        (error) => {
          console.error("Error getting location", error);
          alert("تعذر تحديد الموقع تلقائياً. يرجى التأكد من تفعيل خدمة الموقع أو إدخاله يدوياً.");
          setLocationLoading(false);
        }
      );
    } else {
      alert("الموقع الجغرافي غير مدعوم في هذا المتصفح.");
      setLocationLoading(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!avatarPreview) {
      alert('يرجى رفع صورة شخصية للمتابعة');
      return;
    }

    if (!formData.location) {
      alert('يرجى تحديد موقعك الجغرافي للمتابعة');
      return;
    }

    setLoading(true);

    setTimeout(() => {
      setLoading(false);

      const newUser: User = {
        id: `u-${Date.now()}`,
        username: formData.username.startsWith('@') ? formData.username : `@${formData.username}`,
        fullName: formData.username,
        email: formData.email,
        avatar: avatarPreview || 'https://ui-avatars.com/api/?name=User&background=random',
        gender: 'Male',
        birthDate: '',
        location: formData.location,
        role: UserRole.USER,
        points: 0,
        isPremium: false,
        adsCount: 0,
      };

      onLogin(newUser);
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-primary to-gray-900 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden p-8">
        <div className="text-center mb-6">
          <h1 className="text-4xl font-bold text-primary mb-2">Supply</h1>
          <p className="text-gray-500">منصتك الأولى لتسويق المشاريع</p>
        </div>

        <h2 className="text-2xl font-bold text-gray-800 mb-6 text-center">إنشاء حساب جديد</h2>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div className="flex flex-col items-center justify-center mb-4">
            <div 
              onClick={triggerFileInput}
              className="relative cursor-pointer group"
            >
              <input 
                ref={fileInputRef}
                type="file" 
                accept="image/*" 
                onChange={handleFileChange} 
                className="hidden" 
              />
              <div className={`w-28 h-28 rounded-full border-4 flex items-center justify-center overflow-hidden transition-all ${avatarPreview ? 'border-primary' : 'border-dashed border-gray-300 bg-gray-50 hover:bg-gray-100'}`}>
                {isProcessingImage ? (
                  <Loader2 className="animate-spin text-primary" size={32} />
                ) : avatarPreview ? (
                  <img src={avatarPreview} alt="Preview" className="w-full h-full object-cover" />
                ) : (
                  <div className="text-center text-gray-400">
                    <Camera className="mx-auto mb-1" size={24} />
                    <span className="text-xs font-bold">صورة شخصية</span>
                  </div>
                )}
              </div>

              {avatarPreview ? (
                <button 
                  onClick={clearImage}
                  className="absolute -top-1 -right-1 bg-red-500 text-white p-1 rounded-full shadow-lg hover:bg-red-600 transition-colors"
                >
                  <X size={16} />
                </button>
              ) : (
                <div className="absolute bottom-0 right-0 bg-primary text-white p-2 rounded-full shadow-lg transform translate-x-1 translate-y-1 group-hover:scale-110 transition-transform">
                  <Upload size={16} />
                </div>
              )}
            </div>
            <p className="text-xs text-red-500 mt-2 font-medium">* الصورة الشخصية مطلوبة</p>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1 font-bold">البريد الإلكتروني</label>
            <input 
              type="email" 
              required 
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-primary focus:outline-none" 
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1 font-bold">اسم المستخدم</label>
            <input 
              type="text" 
              required 
              value={formData.username}
              onChange={(e) => setFormData({...formData, username: e.target.value})}
              className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-primary focus:outline-none" 
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1 font-bold">كلمة المرور</label>
            <input 
              type="password" 
              required 
              value={formData.password}
              onChange={(e) => setFormData({...formData, password: e.target.value})}
              className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-primary focus:outline-none" 
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1 font-bold">الموقع الجغرافي <span className="text-red-500">*</span></label>
            <div className="flex gap-2">
              <input 
                type="text" 
                required
                readOnly
                placeholder="لم يتم التحديد بعد"
                value={formData.location}
                className="flex-1 px-4 py-2 border rounded-lg bg-gray-50 text-gray-800 font-medium focus:outline-none cursor-not-allowed" 
              />
              <button
                type="button"
                onClick={handleGetLocation}
                disabled={locationLoading}
                className="bg-primary/10 text-primary hover:bg-primary/20 p-2 rounded-lg transition-colors flex items-center justify-center min-w-[50px]"
                title="تحديد موقعي"
              >
                {locationLoading ? <Loader2 className="animate-spin" size={20} /> : <MapPin size={20} />}
              </button>
            </div>
            <p className="text-xs text-gray-500 mt-1">نحتاج موقعك لتقديم تجربة أفضل وعرض مشاريع قريبة منك.</p>
          </div>

          <button 
            type="submit" 
            disabled={loading || isProcessingImage}
            className="w-full bg-primary text-white py-3 rounded-xl font-bold hover:bg-secondary transition-colors disabled:opacity-70 flex justify-center items-center shadow-lg mt-4"
          >
            {loading ? (
              <Loader2 className="animate-spin" size={20} />
            ) : (
              'إنشاء الحساب'
            )}
          </button>
        </form>

        <div className="mt-6 text-center text-xs text-gray-500">
          بالضغط على زر إنشاء الحساب، أنت توافق على <br />
          <button onClick={() => setCurrentView(View.TERMS)} className="text-primary hover:underline">سياسة الاستخدام</button>
        </div>
      </div>
    </div>
  );
};

